        paint.colorFilter = PorterDuffColorFilter(color, PorterDuff.Mode.SRC_IN)

        // Draw the original icon onto the canvas with the white paint
        canvas.drawBitmap(bitmap, 0f, 0f, paint)

        return whiteBitmap
    }
